I'll provide a complete toy implementation of a relational database query planner that converts SQL AST to relational algebra operations. Below is a Python implementation with classes for AST nodes, relational algebra operations, a query planner, and a simple execution engine.

```python
from abc import ABC, abstractmethod
from typing import List, Dict, Any, Optional

# ========== AST Node Classes ==========
class ASTNode(ABC):
    """Base class for AST nodes"""
    pass

class SelectNode(ASTNode):
    def __init__(self, columns: List[str]):
        self.columns = columns

class FromNode(ASTNode):
    def __init__(self, table_name: str):
        self.table_name = table_name

class WhereNode(ASTNode):
    def __init__(self, condition: Dict[str, Any]):
        # Simple condition format: {'column': 'age', 'op': '>', 'value': 18}
        self.condition = condition

class QueryAST:
    """Container for the entire query AST"""
    def __init__(self, select: SelectNode, from_node: FromNode, where: Optional[WhereNode] = None):
        self.select = select
        self.from_node = from_node
        self.where = where

# ========== Relational Algebra Operations ==========
class RelationalOperation(ABC):
    """Base class for relational algebra operations"""

    @abstractmethod
    def execute(self, data: Dict[str, List[Dict]]) -> List[Dict]:
        """Execute this operation on the given data"""
        pass

class Scan(RelationalOperation):
    """Scan a table"""

    def __init__(self, table_name: str):
        self.table_name = table_name

    def execute(self, data: Dict[str, List[Dict]]) -> List[Dict]:
        return data.get(self.table_name, []).copy()

class Selection(RelationalOperation):
    """Filter rows based on a condition"""

    def __init__(self, input_op: RelationalOperation, condition: Dict[str, Any]):
        self.input_op = input_op
        self.condition = condition

    def _evaluate_condition(self, row: Dict[str, Any]) -> bool:
        """Evaluate a simple condition on a row"""
        col = self.condition['column']
        op = self.condition['op']
        value = self.condition['value']

        if col not in row:
            return False

        if op == '=':
            return row[col] == value
        elif op == '>':
            return row[col] > value
        elif op == '<':
            return row[col] < value
        elif op == '>=':
            return row[col] >= value
        elif op == '<=':
            return row[col] <= value
        elif op == '!=':
            return row[col] != value
        return False

    def execute(self, data: Dict[str, List[Dict]]) -> List[Dict]:
        rows = self.input_op.execute(data)
        return [row for row in rows if self._evaluate_condition(row)]

class Projection(RelationalOperation):
    """Select specific columns"""

    def __init__(self, input_op: RelationalOperation, columns: List[str]):
        self.input_op = input_op
        self.columns = columns

    def execute(self, data: Dict[str, List[Dict]]) -> List[Dict]:
        rows = self.input_op.execute(data)
        result = []
        for row in rows:
            projected = {col: row[col] for col in self.columns if col in row}
            result.append(projected)
        return result

# ========== Query Planner ==========
class QueryPlanner:
    """Converts SQL AST to relational algebra graph"""

    def plan(self, ast: QueryAST) -> RelationalOperation:
        """Build a graph of relational algebra operations from AST"""

        # Start with scanning the table
        scan_op = Scan(ast.from_node.table_name)

        current_op = scan_op

        # Apply WHERE clause if present
        if ast.where:
            current_op = Selection(current_op, ast.where.condition)

        # Apply SELECT columns
        if ast.select.columns:
            # If SELECT is "*", we need to get all columns
            if len(ast.select.columns) == 1 and ast.select.columns[0] == '*':
                # For simplicity, we'll handle this in execution
                current_op = Projection(current_op, ['*'])
            else:
                current_op = Projection(current_op, ast.select.columns)

        return current_op

# ========== Simple Execution Engine ==========
class ToyDatabase:
    """Toy in-memory database with execution engine"""

    def __init__(self):
        self.tables: Dict[str, List[Dict]] = {}

    def create_table(self, name: str, data: List[Dict]):
        """Create a table with sample data"""
        self.tables[name] = data

    def execute_query(self, ast: QueryAST) -> List[Dict]:
        """Execute a query by planning and running it"""
        planner = QueryPlanner()
        plan = planner.plan(ast)
        return plan.execute(self.tables)

# ========== Example Usage ==========
def main():
    # Create a toy database
    db = ToyDatabase()

    # Create a sample table
    employees = [
        {'id': 1, 'name': 'Alice', 'age': 30, 'department': 'Engineering'},
        {'id': 2, 'name': 'Bob', 'age': 25, 'department': 'Sales'},
        {'id': 3, 'name': 'Charlie', 'age': 35, 'department': 'Engineering'},
        {'id': 4, 'name': 'Diana', 'age': 28, 'department': 'Marketing'},
    ]
    db.create_table('employees', employees)

    # Example 1: Simple SELECT with WHERE
    print("Query 1: SELECT name, age FROM employees WHERE age > 28")
    ast1 = QueryAST(
        select=SelectNode(['name', 'age']),
        from_node=FromNode('employees'),
        where=WhereNode({'column': 'age', 'op': '>', 'value': 28})
    )
    result1 = db.execute_query(ast1)
    for row in result1:
        print(f"  {row}")

    # Example 2: SELECT all columns with WHERE
    print("\nQuery 2: SELECT * FROM employees WHERE department = 'Engineering'")
    ast2 = QueryAST(
        select=SelectNode(['*']),
        from_node=FromNode('employees'),
        where=WhereNode({'column': 'department', 'op': '=', 'value': 'Engineering'})
    )
    result2 = db.execute_query(ast2)
    for row in result2:
        print(f"  {row}")

    # Example 3: SELECT without WHERE
    print("\nQuery 3: SELECT name, department FROM employees")
    ast3 = QueryAST(
        select=SelectNode(['name', 'department']),
        from_node=FromNode('employees'),
        where=None
    )
    result3 = db.execute_query(ast3)
    for row in result3:
        print(f"  {row}")

if __name__ == "__main__":
    main()
```

**Key Components Explained:**

1. **AST Representation**: `QueryAST` with `SelectNode`, `FromNode`, and `WhereNode` captures the parsed SQL structure.

2. **Relational Algebra Operations**:
   - `Scan`: Reads all rows from a table
   - `Selection`: Filters rows based on a condition (WHERE clause)
   - `Projection`: Selects specific columns (SELECT clause)

3. **Query Planner**: `QueryPlanner.plan()` builds an execution graph by traversing the AST:
   - Always starts with a `Scan` operation
   - Adds `Selection` if there's a WHERE clause
   - Adds `Projection` for the SELECT columns

4. **Execution Engine**: `ToyDatabase` stores tables in memory and executes queries by:
   - Using the planner to create an operation graph
   - Executing the graph bottom-up (Scan → Selection → Projection)

5. **Example Queries**: The `main()` function demonstrates three queries with different SELECT and WHERE combinations.

**How It Works**:
- The planner converts the declarative SQL into a procedural execution plan
- Operations form a pipeline: each operation takes input from the previous one
- The graph is executed from the leaves (Scan) upward
- Simple condition evaluation supports basic comparison operators

This toy implementation demonstrates the core concepts of query planning in relational databases. You can extend it with JOINs, aggregations, sorting, and more complex optimizations.

