            hasBuyPosition = true;
            break;
        }
    }

    // Trading condition: previous candle closed above EMA AND no existing buy position
    if(!hasBuyPosition && previousClose > emaValue)
    {
        // Calculate stop loss and take profit levels
        double stopLossLevel = 0;
        double takeProfitLevel = 0;

        if(StopLoss > 0)
            stopLossLevel = SymbolInfoDouble(_Symbol, SYMBOL_BID) - StopLoss * _Point;

        if(TakeProfit > 0)
            takeProfitLevel = SymbolInfoDouble(_Symbol, SYMBOL_BID) + TakeProfit * _Point;

        // Place buy order
        MqlTradeRequest request = {};
        MqlTradeResult result = {};

        request.action    = TRADE_ACTION_DEAL;
        request.symbol    = _Symbol;
        request.volume    = LotSize;
        request.type      = ORDER_TYPE_BUY;
        request.price     = SymbolInfoDouble(_Symbol, SYMBOL_ASK);
        request.sl        = stopLossLevel;
        request.tp        = takeProfitLevel;
        request.deviation = 10;
        request.magic     = 12345;
        request.comment   = "Buy above EMA";

        if(OrderSend(request, result))
        {
            if(result.retcode == TRADE_RETCODE_DONE)
                Print("Buy order placed successfully. Ticket: ", result.order);
            else
                Print("OrderSend failed. Retcode: ", result.retcode, " Error: ", GetLastError());
        }
        else
        {
            Print("OrderSend failed. Error: ", GetLastError());
        }
    }
}
```

**Key Features and Corrections:**

1. **Proper EMA Calculation**: Uses `iMA()` with `CopyBuffer()` to get the EMA value for the previous candle (index 1).
2. **Correct Position Checking**: Loops through all positions and checks for buy positions on the current symbol only.
3. **New Bar Detection**: Checks for a new candle using `iTime()` to avoid multiple signals per candle.
4. **Trade Condition**: Checks if the **previous candle** (index 1) closed above the EMA, which is standard practice to avoid repainting.
5. **Modern Trade Execution**: Uses `MqlTradeRequest` and `MqlTradeResult` structures for order placement (recommended in MQL5).
6. **Stop Loss and Take Profit**: Configurable in points; set to 0 to disable.
7. **Error Handling**: Includes proper error checking for indicator creation and order sending.
8. **Resource Management**: Releases the indicator handle in `OnDeinit()`.

**How to Use:**
